func TestActionNames(t *testing.T) {

	reg := makeRegistry(t)
	names := []string{
		"regexp.find",
		"regexp.find_all",
		"regexp.find_all_submatch",
		"regexp.find_submatch",
		"regexp.match",
		"regexp.replace",
		"regexp.replace_literal",
		"regexp.split",
	}
	for _, name := range names {
		a := getAction(t, reg, name)
		if got := a.Name(); got != name {
			t.Errorf("Name() = %q, want %q", got, name)
		}
	}
}

